console.log('🚀 [CHART-MODAL] Loading chart modal functions...');window.chartInstances=window.chartInstances||new Map();let chartModalState={isInitialized:false,modal:null,currentChart:null};window.registerChartInstance=function(canvasId,chartInstance){if(!window.chartInstances){window.chartInstances=new Map();}window.chartInstances.set(canvasId,chartInstance);console.log('✅ [CHART-MODAL] Chart registered:',canvasId);};window.getChartInstance=function(canvasId){if(!window.chartInstances){window.chartInstances=new Map();}const instance=window.chartInstances.get(canvasId);if(instance){console.log('✅ [CHART-MODAL] Chart found in registry:',canvasId);}else{console.log('⚠️ [CHART-MODAL] Chart not found in registry:',canvasId);}return instance;};function waitForChart(callback,maxAttempts=100){if(typeof Chart!=='undefined'){console.log('✅ [CHART-MODAL] Chart.js available');callback();}else if(maxAttempts>0){setTimeout(()=>waitForChart(callback,maxAttempts-1),100);}else{console.error('❌ [CHART-MODAL] Chart.js timeout');}}function setupModalListeners(){if(chartModalState.isInitialized){return;}const modal=document.getElementById('chartFullscreenModal');if(!modal){setTimeout(setupModalListeners,200);return;}console.log('✅ [CHART-MODAL] Modal found in DOM,setting up listeners');chartModalState.modal=modal;modal.addEventListener('click',function(e){if(e.target===this){closeChartModal();}});const closeBtn=modal.querySelector('.chart-modal-close');if(closeBtn){closeBtn.addEventListener('click',function(e){e.preventDefault();closeChartModal();});}document.addEventListener('keydown',function(e){if(e.key==='Escape'&&modal.classList.contains('active')){closeChartModal();}});chartModalState.isInitialized=true;console.log('✅ [CHART-MODAL] Listeners attached to modal');}function openChartModalInternal(chartCanvasId,chartTitle){console.log('📌 [CHART-MODAL] Opening modal for chart:',chartCanvasId);const modal=document.getElementById('chartFullscreenModal');if(!modal){console.error('❌ [CHART-MODAL] Modal not found');return;}const titleEl=document.getElementById('chartModalTitle');if(titleEl){titleEl.textContent=chartTitle;}const originalCanvas=document.getElementById(chartCanvasId);if(!originalCanvas){console.error('❌ [CHART-MODAL] Canvas not found:',chartCanvasId);return;}console.log('✅ [CHART-MODAL] Canvas found');let chartInstance=window.getChartInstance(chartCanvasId);if(!chartInstance){if(originalCanvas.__chartjs__){chartInstance=originalCanvas.__chartjs__;console.log('✅ [CHART-MODAL] Found chart via canvas.__chartjs__');}else if(typeof Chart!=='undefined'&&Chart.helpers&&Chart.helpers.getChart){chartInstance=Chart.helpers.getChart(originalCanvas);if(chartInstance){console.log('✅ [CHART-MODAL] Found chart via Chart.helpers.getChart');}}}if(!chartInstance){console.error('❌ [CHART-MODAL] Chart instance not found');return;}console.log('✅ [CHART-MODAL] Chart instance found,type:',chartInstance.config.type);const modalCanvas=document.getElementById('chartFullscreenCanvas');if(!modalCanvas){console.error('❌ [CHART-MODAL] Modal canvas not found');return;}try{const config={type:chartInstance.config.type,data:JSON.parse(JSON.stringify(chartInstance.config.data)),options:JSON.parse(JSON.stringify(chartInstance.config.options||{}))};config.options.responsive=true;config.options.maintainAspectRatio=false;if(window.currentFullscreenChart){window.currentFullscreenChart.destroy();}window.currentFullscreenChart=new Chart(modalCanvas,config);console.log('✅ [CHART-MODAL] New chart created');modal.classList.add('active');console.log('✅ [CHART-MODAL] Modal displayed');setTimeout(()=>{if(window.currentFullscreenChart){window.currentFullscreenChart.resize();}},100);}catch(error){console.error('❌ [CHART-MODAL] Error creating chart:',error);}}window.openChartModal=function(chartCanvasId,chartTitle){console.log('🔍 [CHART-MODAL] openChartModal called:',chartCanvasId);if(!chartModalState.isInitialized){console.log('📌 [CHART-MODAL] Modal not initialized yet,initializing now...');setupModalListeners();}const modal=document.getElementById('chartFullscreenModal');if(!modal){console.error('❌ [CHART-MODAL] Modal still not found in DOM after initialization');console.log('📌 [CHART-MODAL] Will retry initialization in 100ms...');setTimeout(()=>window.openChartModal(chartCanvasId,chartTitle),100);return;}if(typeof Chart==='undefined'){console.warn('⏳ [CHART-MODAL] Waiting for Chart.js...');waitForChart(()=>openChartModalInternal(chartCanvasId,chartTitle));return;}openChartModalInternal(chartCanvasId,chartTitle);};window.closeChartModal=function(){console.log('🔴 [CHART-MODAL] closeChartModal called');const modal=document.getElementById('chartFullscreenModal');if(modal){modal.classList.remove('active');}if(window.currentFullscreenChart){window.currentFullscreenChart.destroy();window.currentFullscreenChart=null;}console.log('✅ [CHART-MODAL] Modal closed');};console.log('📌 [CHART-MODAL] Document ready state:',document.readyState);if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',function(){console.log('📌 [CHART-MODAL] DOMContentLoaded fired,initializing...');setupModalListeners();});}else{console.log('📌 [CHART-MODAL] DOM already loaded,initializing now...');setupModalListeners();}console.log('✅ [CHART-MODAL] Script loaded!Available functions:');console.log(' window.openChartModal(canvasId,title)');console.log(' window.closeChartModal()');console.log(' window.registerChartInstance(canvasId,chartInstance)');console.log(' window.getChartInstance(canvasId)');